import sys
from collections import deque

def solve():
    data = sys.stdin.buffer.read().split()
    ptr = 0
    H = int(data[ptr]); ptr += 1
    W = int(data[ptr]); ptr += 1
    T = int(data[ptr]); ptr += 1

    grid = []
    for i in range(H):
        grid.append(data[ptr].decode()); ptr += 1

    start = goal = None
    candies = []
    for i in range(H):
        row = grid[i]
        for j in range(W):
            c = row[j]
            if c == 'S': start = (i, j)
            elif c == 'G': goal = (i, j)
            elif c == 'o': candies.append((i, j))

    n = len(candies)
    nodes = [start, goal] + candies
    K = len(nodes)
    INF = 10**9
    dist_all = [[INF] * K for _ in range(K)]

    for a in range(K):
        si, sj = nodes[a]
        d = [[-1] * W for _ in range(H)]
        d[si][sj] = 0
        q = deque([(si, sj)])
        while q:
            ci, cj = q.popleft()
            nd = d[ci][cj] + 1
            if ci > 0 and d[ci-1][cj] < 0 and grid[ci-1][cj] != '#':
                d[ci-1][cj] = nd; q.append((ci-1, cj))
            if ci < H-1 and d[ci+1][cj] < 0 and grid[ci+1][cj] != '#':
                d[ci+1][cj] = nd; q.append((ci+1, cj))
            if cj > 0 and d[ci][cj-1] < 0 and grid[ci][cj-1] != '#':
                d[ci][cj-1] = nd; q.append((ci, cj-1))
            if cj < W-1 and d[ci][cj+1] < 0 and grid[ci][cj+1] != '#':
                d[ci][cj+1] = nd; q.append((ci, cj+1))
        for b in range(K):
            ti, tj = nodes[b]
            if d[ti][tj] >= 0:
                dist_all[a][b] = d[ti][tj]

    if dist_all[0][1] > T:
        print(-1); return
    if n == 0:
        print(0); return

    dist_s = [dist_all[0][i+2] for i in range(n)]
    dist_g = [dist_all[i+2][1] for i in range(n)]
    cc = [[dist_all[i+2][j+2] for j in range(n)] for i in range(n)]

    SIZE = 1 << n
    dp = [[INF] * n for _ in range(SIZE)]
    for i in range(n):
        dp[1 << i][i] = dist_s[i]

    for mask in range(1, SIZE):
        dpm = dp[mask]
        for i in range(n):
            if not (mask >> i & 1): continue
            vi = dpm[i]
            if vi >= T: continue
            cci = cc[i]
            for j in range(n):
                if mask >> j & 1: continue
                nv = vi + cci[j]
                if nv >= T: continue
                nmask = mask | (1 << j)
                if nv < dp[nmask][j]:
                    dp[nmask][j] = nv

    ans = 0
    for mask in range(1, SIZE):
        cnt = bin(mask).count('1')
        if cnt <= ans: continue
        dpm = dp[mask]
        for i in range(n):
            if (mask >> i & 1) and dpm[i] + dist_g[i] <= T:
                ans = cnt; break
        if ans == n: break
    print(ans)

solve()

import sys

def solve():
    data = sys.stdin.read().split()
    N = int(data[0])
    A = list(map(int, data[1:N+1]))
    S = data[N+1]

    # Precompute mex table
    mex_table = [[[0]*3 for _ in range(3)] for _ in range(3)]
    for a in range(3):
        for b in range(3):
            for c in range(3):
                s = {a, b, c}
                for v in range(4):
                    if v not in s:
                        mex_table[a][b][c] = v
                        break

    # Suffix counts of X positions with each value
    suffix_x = [[0]*3 for _ in range(N+1)]
    for i in range(N-1, -1, -1):
        for c in range(3):
            suffix_x[i][c] = suffix_x[i+1][c]
        if S[i] == 'X':
            suffix_x[i][A[i]] += 1

    prefix_m = [0, 0, 0]
    total = 0

    for j in range(N):
        if S[j] == 'E':
            b = A[j]
            sx = suffix_x[j+1]
            for a in range(3):
                pm = prefix_m[a]
                if pm == 0:
                    continue
                for c in range(3):
                    m = mex_table[a][b][c]
                    if m > 0 and sx[c] > 0:
                        total += pm * sx[c] * m
        if S[j] == 'M':
            prefix_m[A[j]] += 1

    print(total)

solve()

import sys

def main():
    data = sys.stdin.buffer.read().split()
    idx = 0
    N = int(data[idx]); idx += 1
    M = int(data[idx]); idx += 1

    children = [[] for _ in range(N + 1)]
    for i in range(2, N + 1):
        p = int(data[idx]); idx += 1
        children[p].append(i)

    cov = [-1] * (N + 1)

    for _ in range(M):
        x = int(data[idx]); idx += 1
        y = int(data[idx]); idx += 1
        if y > cov[x]:
            cov[x] = y

    for i in range(1, N + 1):
        if cov[i] > 0:
            for c in children[i]:
                v = cov[i] - 1
                if v > cov[c]:
                    cov[c] = v

    ans = 0
    for i in range(1, N + 1):
        if cov[i] >= 0:
            ans += 1
    print(ans)

main()
